// ─── PARTICLES ───────────────────────────────────────────────
function Particles() {
  const particles = Array.from({length: 28}, (_, i) => ({
    id: i,
    x: Math.random() * 100,
    duration: 8 + Math.random() * 14,
    delay: Math.random() * 10,
    size: Math.random() > 0.7 ? 2 : 1,
    opacity: 0.15 + Math.random() * 0.35,
  }));
  return (
    <div style={{ position:"fixed", inset:0, pointerEvents:"none", zIndex:1, overflow:"hidden" }}>
      {particles.map(p => (
        <div key={p.id} style={{
          position:"absolute", left:`${p.x}%`, bottom:"-10px",
          width:`${p.size}px`, height:`${p.size}px`,
          background:"#00ff41", borderRadius:"50%",
          opacity: p.opacity,
          animation:`floatUp ${p.duration}s ${p.delay}s infinite linear`,
        }}/>
      ))}
    </div>
  );
}

// ─── GLITCH TEXT ─────────────────────────────────────────────
function GlitchText({ text, style }) {
  return (
    <div style={{ position:"relative", display:"inline-block", ...style }}>
      <span style={{ position:"relative", zIndex:2 }}>{text}</span>
      <span style={{ position:"absolute", top:0, left:"2px", color:"#ff0055", opacity:0.6, zIndex:1, animation:"glitchA 3.5s infinite" }} aria-hidden>{text}</span>
      <span style={{ position:"absolute", top:0, left:"-2px", color:"#00ffff", opacity:0.5, zIndex:1, animation:"glitchB 3.5s infinite" }} aria-hidden>{text}</span>
    </div>
  );
}

// ─── TYPEWRITER ───────────────────────────────────────────────
function Typewriter({ text, speed=16, onDone }) {
  const [displayed, setDisplayed] = useState("");
  const [done, setDone] = useState(false);
  useEffect(() => {
    setDisplayed(""); setDone(false);
    let i = 0;
    const t = setInterval(() => {
      i++;
      setDisplayed(text.slice(0, i));
      if (i >= text.length) { clearInterval(t); setDone(true); onDone && onDone(); }
    }, speed);
    return () => clearInterval(t);
  }, [text]);
  return (
    <span>
      {displayed.split("\n").map((line, i, arr) => (
        <span key={i}>{line}{i < arr.length - 1 && <br/>}</span>
      ))}
      {!done && <span style={{ animation:"blink 0.7s infinite", color:"#00ff41" }}>▌</span>}
    </span>
  );
}

// ─── SCENE IMAGE ──────────────────────────────────────────────
function SceneImage({ src, emoji, reveal }) {
  const [loaded, setLoaded] = useState(false);
  if (!src) return (
    <div style={{ width:"100%",height:"160px",background:"rgba(0,255,65,0.02)",border:"1px dashed #00ff4120",borderRadius:"3px",display:"flex",alignItems:"center",justifyContent:"center",marginBottom:"1.4rem",gap:"0.6rem" }}>
      <span style={{ fontSize:"2rem" }}>{emoji}</span>
      <span style={{ fontSize:"0.62rem",color:"#003311",letterSpacing:"0.1em" }}>// SCENE PHOTO LOADING SOON</span>
    </div>
  );
  return (
    <div style={{ position:"relative",marginBottom:"1.4rem",borderRadius:"3px",overflow:"hidden",lineHeight:0,
      opacity: reveal ? 1 : 0,
      transform: reveal ? "scale(1)" : "scale(1.04)",
      transition: "opacity 0.9s ease, transform 1.1s ease",
    }}>
      {!loaded && (
        <div style={{ width:"100%",height:"200px",background:"#050d05",display:"flex",alignItems:"center",justifyContent:"center" }}>
          <span style={{ color:"#003311",fontSize:"0.7rem",letterSpacing:"0.1em",animation:"blink 1s infinite" }}>LOADING SCENE...</span>
        </div>
      )}
      <img src={src} onLoad={()=>setLoaded(true)} alt="scene" style={{
        width:"100%", maxHeight:"270px", objectFit:"cover", objectPosition:"center top",
        display:loaded?"block":"none",
        filter:"brightness(0.78) contrast(1.12) saturate(1.15)",
        transition:"filter 1s ease",
      }}/>
      {/* Cinematic overlays */}
      <div style={{ position:"absolute",inset:0,background:"radial-gradient(ellipse at 50% 50%,transparent 30%,rgba(0,0,0,0.78) 100%)",pointerEvents:"none" }}/>
      <div style={{ position:"absolute",inset:0,background:"linear-gradient(to bottom, rgba(0,255,65,0.03) 0%, transparent 30%, rgba(0,0,0,0.6) 100%)",pointerEvents:"none" }}/>
      {/* Scan line sweep */}
      <div style={{ position:"absolute",inset:0,background:"repeating-linear-gradient(0deg,transparent,transparent 3px,rgba(0,255,65,0.015) 3px,rgba(0,255,65,0.015) 4px)",pointerEvents:"none",animation:"scanMove 8s linear infinite" }}/>
      {/* Bottom fade */}
      <div style={{ position:"absolute",bottom:0,left:0,right:0,height:"70px",background:"linear-gradient(transparent,rgba(0,5,1,0.95))",pointerEvents:"none" }}/>
    </div>
  );
}

// ─── LOADING BAR ──────────────────────────────────────────────
function LoadingBar({ onComplete }) {
  const [p, setP] = useState(0);
  useEffect(() => {
    let s=0; const t=setInterval(()=>{ s++; setP(s); if(s>=20){clearInterval(t);setTimeout(onComplete,400);} },110);
    return ()=>clearInterval(t);
  },[]);
  return (
    <div style={{ margin:"1.5rem 0", animation:"fadeSlideIn 0.3s ease" }}>
      <div style={{ color:"#00cc33",fontSize:"0.72rem",letterSpacing:"0.12em",marginBottom:"0.5rem" }}>◈ CROSS-REFERENCING CASE ARCHIVES...</div>
      <div style={{ color:"#00ff41",fontSize:"1rem",fontFamily:"'Share Tech Mono',monospace",textShadow:`0 0 ${p*2}px #00ff4166` }}>
        [{Array(p).fill("▓").join("")}{Array(20-p).fill("░").join("")}] {Math.floor((p/20)*100)}%
      </div>
    </div>
  );
}

// ─── BOOT SCREEN ─────────────────────────────────────────────
function BootScreen({ onComplete }) {
  const [vis, setVis] = useState(0);
  const lines = [
    {t:"INITIALIZING CASE MANAGEMENT SYSTEM v2.7...",c:"#00cc33"},
    {t:"LOADING ENCRYPTED CASE FILES......",c:"#00cc33"},
    {t:"AUTHENTICATION REQUIRED.",c:"#00cc33"},
    {t:"WELCOME, DETECTIVE KAMMO.",c:"#00ffaa"},
    {t:"12 MEMORIES STOLEN. 12 LEVELS TO RESTORE.",c:"#ffcc00"},
    {t:"THE TIMELINE IS WAITING.",c:"#ff88cc"},
  ];
  useEffect(()=>{
    const ts=lines.map((_,i)=>setTimeout(()=>setVis(v=>Math.max(v,i+1)),i*750+500));
    const done=setTimeout(onComplete,lines.length*750+1600);
    return ()=>{ts.forEach(clearTimeout);clearTimeout(done);};
  },[]);
  return (
    <div style={{ minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:"2rem",position:"relative" }}>
      <Particles/>
      <div style={{ maxWidth:"700px",width:"100%",position:"relative",zIndex:2 }}>
        <div style={{ fontFamily:"'Rajdhani',sans-serif",fontSize:"clamp(1rem,3vw,1.4rem)",color:"#003311",letterSpacing:"0.35em",textTransform:"uppercase",marginBottom:"0.4rem",animation:"fadeSlideIn 0.8s ease" }}>
          THE CASE OF THE
        </div>
        <div style={{ marginBottom:"3rem" }}>
          <GlitchText text="STOLEN TIMELINE" style={{
            fontFamily:"'Orbitron',monospace",
            fontSize:"clamp(1.4rem,5vw,2.8rem)",
            color:"#00ff41",
            letterSpacing:"0.12em",
            textShadow:"0 0 30px #00ff4166",
            display:"block",
          }}/>
        </div>
        {lines.slice(0,vis).map((l,i)=>(
          <div key={i} style={{ fontSize:"clamp(0.68rem,1.8vw,0.85rem)",color:l.c,marginBottom:"0.55rem",letterSpacing:"0.07em",animation:"fadeSlideIn 0.4s ease" }}>
            <span style={{ color:"#005511",marginRight:"0.5rem" }}>▶</span>{l.t}
          </div>
        ))}
        {vis>0&&<span style={{ color:"#00ff41",animation:"blink 0.7s infinite",display:"inline-block" }}>█</span>}
      </div>
    </div>
  );
}

// ─── LEVEL SCREEN ─────────────────────────────────────────────
function LevelScreen({ level, onSolve }) {
  const [input, setInput] = useState("");
  const [phase, setPhase] = useState("entering"); // entering|riddle|checking|granted|denied
  const [attempts, setAttempts] = useState(0);
  const [riddleDone, setRiddleDone] = useState(false);
  const [imageReveal, setImageReveal] = useState(false);
  const inputRef = useRef(null);

  useEffect(()=>{
    // Staggered entrance
    const t1 = setTimeout(()=>setImageReveal(true), 400);
    const t2 = setTimeout(()=>setPhase("riddle"), 300);
    return ()=>{ clearTimeout(t1); clearTimeout(t2); };
  },[]);

  useEffect(()=>{ if(phase==="riddle" && riddleDone) setTimeout(()=>inputRef.current?.focus(),100); },[phase, riddleDone]);

  const checkPassword = ()=>{ if(!input.trim()||phase==="checking") return; setPhase("checking"); };
  const handleResult = ()=>{
    const n=input.trim().toLowerCase().replace(/[^a-z0-9 ]/g,"");
    const ok=level.password.some(p=>{ const pn=p.toLowerCase().replace(/[^a-z0-9 ]/g,""); return n===pn||n.includes(pn)||pn.includes(n); });
    if(ok){setPhase("granted");}else{setAttempts(a=>a+1);setPhase("denied");setTimeout(()=>{setInput("");setPhase("riddle");},2800);}
  };
  const bar=Array(level.id).fill("▓").join("")+Array(12-level.id).fill("░").join("");

  return (
    <div style={{ minHeight:"100vh",display:"flex",alignItems:"flex-start",justifyContent:"center",padding:"2.5rem 1rem",position:"relative" }}>
      <Particles/>
      <div style={{
        width:"100%", maxWidth:"800px",
        border:"1px solid #00ff4133", borderRadius:"4px",
        background:"rgba(0,8,2,0.97)",
        boxShadow:"0 0 60px rgba(0,255,65,0.07), 0 0 120px rgba(0,255,65,0.03)",
        position:"relative", zIndex:2,
        animation:"terminalEntry 0.6s cubic-bezier(0.16,1,0.3,1) forwards",
      }}>
        {/* Corner accents */}
        <div style={{ position:"absolute",top:-1,left:-1,width:20,height:20,borderTop:"2px solid #00ff41",borderLeft:"2px solid #00ff41",borderRadius:"4px 0 0 0" }}/>
        <div style={{ position:"absolute",top:-1,right:-1,width:20,height:20,borderTop:"2px solid #00ff41",borderRight:"2px solid #00ff41",borderRadius:"0 4px 0 0" }}/>
        <div style={{ position:"absolute",bottom:-1,left:-1,width:20,height:20,borderBottom:"2px solid #00ff41",borderLeft:"2px solid #00ff41",borderRadius:"0 0 0 4px" }}/>
        <div style={{ position:"absolute",bottom:-1,right:-1,width:20,height:20,borderBottom:"2px solid #00ff41",borderRight:"2px solid #00ff41",borderRadius:"0 0 4px 0" }}/>

        {/* Header */}
        <div style={{ display:"flex",alignItems:"center",padding:"0.6rem 1rem",background:"#060e06",borderBottom:"1px solid #00ff4120",borderRadius:"4px 4px 0 0",gap:"0.8rem" }}>
          <div style={{ display:"flex",gap:"6px" }}>
            {["#ff5f57","#febc2e","#28c840"].map(c=>(<span key={c} style={{ width:11,height:11,borderRadius:"50%",background:c,display:"inline-block",boxShadow:`0 0 6px ${c}88` }}/>))}
          </div>
          <div style={{ flex:1,textAlign:"center",fontSize:"0.65rem",color:"#006622",letterSpacing:"0.1em" }}>
            DETECTIVE_KAMMO :: CASE_FILE_{String(level.id).padStart(3,"0")}
          </div>
          <div style={{ fontSize:"0.6rem",color:"#00ff4166",border:"1px solid #00ff4122",padding:"2px 7px",borderRadius:"2px",animation:"pulseGlow 2s infinite" }}>{level.id}/12</div>
        </div>

        <div style={{ padding:"2rem" }}>
          {/* Progress */}
          <div style={{ fontSize:"0.6rem",color:"#004411",marginBottom:"1.2rem",letterSpacing:"0.05em",animation:"fadeSlideIn 0.5s ease" }}>
            CASE PROGRESS: [{bar}]
            <span style={{ marginLeft:"1rem",color:"#006622" }}>{Math.floor((level.id/12)*100)}% RESTORED</span>
          </div>

          {/* Title with glitch */}
          <div style={{ marginBottom:"0.8rem",animation:"fadeSlideIn 0.6s 0.1s ease both" }}>
            <GlitchText text={level.title} style={{
              fontFamily:"'Orbitron',monospace",
              fontSize:"clamp(0.6rem,2vw,0.82rem)",
              color:"#00ffaa",
              letterSpacing:"0.12em",
              textShadow:"0 0 15px #00ffaa44",
            }}/>
          </div>

          <div style={{ color:"#003311",fontSize:"0.75rem",marginBottom:"1.2rem",overflow:"hidden",animation:"expandWidth 0.8s 0.2s ease both" }}>{"─".repeat(60)}</div>

          {/* Scene image */}
          <div style={{ animation:"fadeSlideIn 0.7s 0.15s ease both" }}>
            <SceneImage src={IMGS[level.imgKey]} emoji={level.emoji} reveal={imageReveal}/>
          </div>

          {/* Riddle */}
          <div style={{ marginBottom:"1.8rem",animation:"fadeSlideIn 0.6s 0.25s ease both" }}>
            <div style={{ fontSize:"0.62rem",color:"#00aa33",letterSpacing:"0.15em",marginBottom:"0.7rem",display:"flex",alignItems:"center",gap:"0.5rem" }}>
              <span style={{ animation:"blink 1s infinite" }}>▶</span> INCOMING TRANSMISSION
            </div>
            <div style={{ fontSize:"clamp(0.78rem,2.2vw,0.93rem)",color:"#00dd44",lineHeight:1.9,letterSpacing:"0.025em" }}>
              {phase !== "entering" && (
                <Typewriter text={level.riddle} speed={14} onDone={()=>setRiddleDone(true)}/>
              )}
            </div>
          </div>

          {/* Hint */}
          {attempts>0 && phase!=="granted" && (
            <div style={{ background:"rgba(255,204,0,0.03)",border:"1px solid rgba(255,204,0,0.18)",borderRadius:"2px",padding:"1rem 1.2rem",marginBottom:"1.5rem",animation:"fadeSlideIn 0.4s ease" }}>
              <div style={{ fontSize:"0.6rem",color:"#cc9900",letterSpacing:"0.15em",marginBottom:"0.5rem",display:"flex",alignItems:"center",gap:"0.4rem" }}>
                <span style={{ animation:"blink 1.2s infinite" }}>◈</span> DETECTIVE HINT [{attempts} FAILED ATTEMPT{attempts!==1?"S":""}]
              </div>
              <div style={{ fontSize:"0.82rem",color:"#ffcc00bb",lineHeight:1.75 }}>{level.hint}</div>
            </div>
          )}

          {/* Input */}
          {phase==="riddle" && riddleDone && (
            <div style={{ animation:"fadeSlideIn 0.5s ease" }}>
              <div style={{ fontSize:"0.62rem",color:"#00aa33",letterSpacing:"0.15em",marginBottom:"0.7rem",display:"flex",alignItems:"center",gap:"0.4rem" }}>
                <span style={{ animation:"blink 1s infinite" }}>▶</span> ENTER PASSWORD TO DECRYPT
              </div>
              <div style={{ display:"flex",alignItems:"center",borderBottom:"1px solid #00ff4130",paddingBottom:"0.4rem",marginBottom:"1rem",flexWrap:"wrap",gap:"0.3rem",
                animation:"expandWidth 0.6s ease" }}>
                <span style={{ color:"#00aa33",fontSize:"0.78rem",whiteSpace:"nowrap" }}>root@detective ~$ </span>
                <input ref={inputRef} value={input}
                  onChange={e=>setInput(e.target.value)}
                  onKeyDown={e=>e.key==="Enter"&&checkPassword()}
                  style={{ background:"transparent",border:"none",outline:"none",color:"#00ff41",fontFamily:"'Share Tech Mono',monospace",fontSize:"clamp(0.85rem,2.5vw,1rem)",flex:1,caretColor:"#00ff41",minWidth:"120px" }}
                  placeholder="type your answer..." autoComplete="off" spellCheck={false}/>
              </div>
              <button onClick={checkPassword}
                style={{ background:"transparent",border:"1px solid #00ff4166",color:"#00ff41",fontFamily:"'Share Tech Mono',monospace",fontSize:"0.78rem",padding:"0.55rem 1.4rem",cursor:"pointer",letterSpacing:"0.1em",transition:"all 0.25s",position:"relative",overflow:"hidden" }}
                onMouseEnter={e=>{e.currentTarget.style.background="#00ff4115";e.currentTarget.style.boxShadow="0 0 20px #00ff4144";e.currentTarget.style.letterSpacing="0.18em";}}
                onMouseLeave={e=>{e.currentTarget.style.background="transparent";e.currentTarget.style.boxShadow="none";e.currentTarget.style.letterSpacing="0.1em";}}>
                [ DECRYPT FILE ]
              </button>
            </div>
          )}

          {/* Input visible but locked while typing */}
          {phase==="riddle" && !riddleDone && (
            <div style={{ opacity:0.3,fontSize:"0.62rem",color:"#004411",letterSpacing:"0.15em",marginTop:"1rem" }}>
              ▶ AWAITING TRANSMISSION...
            </div>
          )}

          {phase==="checking" && <LoadingBar onComplete={handleResult}/>}

          {phase==="denied" && (
            <div style={{ background:"rgba(255,30,50,0.05)",border:"1px solid rgba(255,30,50,0.3)",borderRadius:"2px",padding:"1.2rem",animation:"shakeX 0.5s ease" }}>
              <div style={{ fontFamily:"'Orbitron',monospace",color:"#ff3344",fontSize:"clamp(0.75rem,2vw,0.95rem)",letterSpacing:"0.1em",marginBottom:"0.6rem",textShadow:"0 0 20px #ff334466",animation:"flickerRed 0.3s ease 3" }}>⛔ [ ACCESS DENIED ]</div>
              <div style={{ color:"#ff334488",fontSize:"0.8rem",lineHeight:1.7 }}>The archives don't recognize that, Detective. The memory remains locked. Try again — you're closer than you think.</div>
            </div>
          )}

          {phase==="granted" && (
            <div style={{ animation:"fadeSlideIn 0.5s ease" }}>
              <div style={{ fontFamily:"'Orbitron',monospace",color:"#00ffaa",fontSize:"clamp(0.8rem,2.5vw,1.05rem)",letterSpacing:"0.12em",marginBottom:"1rem",textShadow:"0 0 25px #00ffaa88",animation:"pulseGlow 1.5s infinite" }}>✅ [ ACCESS GRANTED ]</div>
              <div style={{ color:"#003311",fontSize:"0.75rem",marginBottom:"1rem",overflow:"hidden" }}>{"─".repeat(60)}</div>
              <div style={{ fontSize:"0.62rem",color:"#00aa33",letterSpacing:"0.15em",marginBottom:"0.7rem",display:"flex",alignItems:"center",gap:"0.4rem" }}>
                <span style={{ animation:"blink 0.8s infinite" }}>◈</span> MEMORY RESTORED — DECRYPTING...
              </div>
              <div style={{ fontSize:"clamp(0.78rem,2vw,0.9rem)",color:"#88ffcc",lineHeight:1.95,padding:"1.2rem",background:"rgba(0,255,150,0.025)",border:"1px solid rgba(0,255,150,0.1)",borderRadius:"2px",marginBottom:"1.5rem",animation:"expandHeight 0.6s ease",boxShadow:"inset 0 0 30px rgba(0,255,150,0.03)" }}>
                {level.memory.split("\n").map((l,i)=><span key={i}>{l}{i<level.memory.split("\n").length-1&&<br/>}</span>)}
              </div>
              <div style={{ color:"#003311",fontSize:"0.75rem",marginBottom:"1.2rem",overflow:"hidden" }}>{"─".repeat(60)}</div>
              <button onClick={onSolve}
                style={{ background:level.id===12?"linear-gradient(90deg,#ff88cc,#cc44aa)":"transparent",border:level.id===12?"none":"1px solid #00ffaa88",color:level.id===12?"#000":"#00ffaa",fontFamily:"'Share Tech Mono',monospace",fontSize:"0.78rem",padding:"0.6rem 1.5rem",cursor:"pointer",letterSpacing:"0.1em",fontWeight:level.id===12?"bold":"normal",transition:"all 0.25s",animation:"pulseGlow 2s infinite" }}
                onMouseEnter={e=>{e.currentTarget.style.transform="translateX(4px)";e.currentTarget.style.letterSpacing="0.16em";}}
                onMouseLeave={e=>{e.currentTarget.style.transform="translateX(0)";e.currentTarget.style.letterSpacing="0.1em";}}>
                {level.id<12?`[ PROCEED TO CASE FILE #${String(level.id+1).padStart(3,"0")} ] →`:"[ RESTORE THE TIMELINE ] ✦"}
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── FINALE ───────────────────────────────────────────────────
function FinaleScreen() {
  const [phase, setPhase] = useState(0);
  const [particles] = useState(() => Array.from({length:50}, (_,i) => ({
    id:i, x:Math.random()*100, dur:6+Math.random()*10,
    delay:Math.random()*5, color: i%3===0?"#ff88cc":i%3===1?"#ffd700":"#00ffaa",
    size: 1+Math.random()*3,
  })));
  useEffect(()=>{ [0,800,2000,3400,5000,6600,8200,9800].forEach((d,i)=>setTimeout(()=>setPhase(i+1),d)); },[]);
  return (
    <div style={{ minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:"3rem 2rem",background:"radial-gradient(ellipse at 50% 40%,#100820 0%,#030303 65%)",fontFamily:"'Rajdhani',sans-serif",position:"relative",overflow:"hidden" }}>
      {/* Coloured finale particles */}
      <div style={{ position:"fixed",inset:0,pointerEvents:"none",zIndex:1 }}>
        {particles.map(p=>(
          <div key={p.id} style={{ position:"absolute",left:`${p.x}%`,bottom:"-10px",width:`${p.size}px`,height:`${p.size}px`,background:p.color,borderRadius:"50%",opacity:0.4,animation:`floatUp ${p.dur}s ${p.delay}s infinite linear` }}/>
        ))}
      </div>
      <div style={{ maxWidth:"700px",width:"100%",textAlign:"center",position:"relative",zIndex:2 }}>
        {phase>=1&&<div style={{ fontSize:"4.5rem",marginBottom:"1.5rem",animation:"heartbeat 2s infinite, fadeSlideIn 1s ease" }}>🌅</div>}
        {phase>=2&&(
          <div style={{ fontFamily:"'Orbitron',monospace",fontSize:"clamp(1.4rem,5vw,2.6rem)",color:"#ffffff",letterSpacing:"0.07em",lineHeight:1.3,marginBottom:"1rem",textShadow:"0 0 50px rgba(255,255,255,0.15)",animation:"fadeSlideIn 1s ease" }}>
            THE TIMELINE IS<br/>
            <span style={{ color:"#ffd700",textShadow:"0 0 50px #ffd70088",display:"inline-block",animation:"pulseGold 2s infinite" }}>FULLY RESTORED</span>
          </div>
        )}
        {phase>=3&&<div style={{ color:"#ffd700",fontSize:"1.4rem",margin:"1.2rem 0",letterSpacing:"0.5em",animation:"fadeSlideIn 0.8s ease, pulseGold 2s infinite" }}>✦ ✦ ✦</div>}
        {phase>=4&&(
          <div style={{ fontSize:"clamp(0.95rem,2.5vw,1.15rem)",color:"#ccffee",lineHeight:1.9,marginBottom:"1.5rem",fontWeight:300,animation:"fadeSlideIn 1s ease" }}>
            Congratulations, <span style={{ color:"#ff88cc",fontWeight:600,textShadow:"0 0 20px #ff88cc66" }}>Detective Kammo</span>.<br/><br/>
            You found all 12 stolen memories and cracked every case file.<br/>The timeline is complete. Every moment — accounted for.
          </div>
        )}
        {phase>=5&&(
          <div style={{ fontSize:"clamp(0.88rem,2.2vw,1.05rem)",color:"#9999bb",lineHeight:1.9,marginBottom:"1.8rem",fontStyle:"italic",padding:"0 1rem",animation:"fadeSlideIn 1s ease" }}>
            And somewhere in Panvel, the guy who spoofed his GPS, bunked his internship,<br/>flew at 3 AM, and decorated a room in Udaipur — just wants you to know:
          </div>
        )}
        {phase>=6&&(
          <div style={{ fontFamily:"'Orbitron',monospace",fontSize:"clamp(1.5rem,5vw,2.5rem)",color:"#ff88cc",lineHeight:1.5,marginBottom:"1rem",textShadow:"0 0 40px #ff88cc77",animation:"heartbeat 1.8s infinite, fadeSlideIn 1s ease" }}>
            he loves you.
          </div>
        )}
        {phase>=7&&(
          <div style={{ fontFamily:"'Share Tech Mono',monospace",fontSize:"clamp(0.72rem,1.8vw,0.88rem)",color:"#aaffcc",letterSpacing:"0.1em",marginBottom:"2rem",animation:"fadeSlideIn 1s ease",textShadow:"0 0 15px #aaffcc44" }}>
            the greatest glitch in history was the one that brought you here.
          </div>
        )}
        {phase>=8&&<div style={{ fontFamily:"'Share Tech Mono',monospace",fontSize:"0.85rem",color:"#555",letterSpacing:"0.06em",animation:"fadeSlideIn 1s ease" }}>— The Guy from Panvel 🖤</div>}
      </div>
    </div>
  );
}

export default function StolenTimeline() {
  const [appPhase, setAppPhase] = useState("boot");
  const [currentLevel, setCurrentLevel] = useState(0);
  const handleSolve = ()=>{ if(currentLevel>=LEVELS.length-1) setAppPhase("finale"); else setCurrentLevel(l=>l+1); };
  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Share+Tech+Mono&family=Orbitron:wght@400;700;900&family=Rajdhani:wght@300;400;600&display=swap');
        *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
        html,body{background:#030303}
        ::-webkit-scrollbar{width:5px}::-webkit-scrollbar-track{background:#080808}::-webkit-scrollbar-thumb{background:#00ff4130;border-radius:3px}

        @keyframes blink{0%,100%{opacity:1}50%{opacity:0}}
        @keyframes heartbeat{0%,100%{transform:scale(1)}14%{transform:scale(1.12)}28%{transform:scale(1)}42%{transform:scale(1.06)}70%{transform:scale(1)}}
        @keyframes flicker{0%,89%,91%,93%,100%{opacity:1}90%{opacity:0.82}92%{opacity:0.95}}
        @keyframes floatUp{0%{transform:translateY(0) translateX(0);opacity:0}10%{opacity:1}90%{opacity:0.3}100%{transform:translateY(-100vh) translateX(20px);opacity:0}}
        @keyframes glitchA{0%,100%{clip-path:none;transform:none}2%{clip-path:inset(40% 0 50% 0);transform:translateX(-3px)}4%{clip-path:inset(70% 0 10% 0);transform:translateX(3px)}6%{clip-path:none;transform:none}96%{clip-path:inset(20% 0 60% 0);transform:translateX(2px)}98%{clip-path:none}}
        @keyframes glitchB{0%,100%{clip-path:none;transform:none}3%{clip-path:inset(30% 0 55% 0);transform:translateX(3px)}5%{clip-path:inset(60% 0 25% 0);transform:translateX(-2px)}7%{clip-path:none;transform:none}97%{clip-path:inset(50% 0 30% 0);transform:translateX(-3px)}}
        @keyframes fadeSlideIn{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:translateY(0)}}
        @keyframes terminalEntry{from{opacity:0;transform:translateY(20px) scale(0.98)}to{opacity:1;transform:translateY(0) scale(1)}}
        @keyframes expandWidth{from{opacity:0;transform:scaleX(0.4);transform-origin:left}to{opacity:1;transform:scaleX(1)}}
        @keyframes expandHeight{from{opacity:0;max-height:0;overflow:hidden}to{opacity:1;max-height:600px}}
        @keyframes pulseGlow{0%,100%{opacity:1}50%{opacity:0.75}}
        @keyframes pulseGold{0%,100%{text-shadow:0 0 50px #ffd70088}50%{text-shadow:0 0 80px #ffd700cc,0 0 120px #ffd70044}}
        @keyframes shakeX{0%,100%{transform:translateX(0)}20%{transform:translateX(-8px)}40%{transform:translateX(8px)}60%{transform:translateX(-5px)}80%{transform:translateX(5px)}}
        @keyframes flickerRed{0%,100%{opacity:1}50%{opacity:0.4}}
        @keyframes scanMove{0%{background-position:0 0}100%{background-position:0 100%}}
      `}</style>
      <div style={{ position:"fixed",top:0,left:0,right:0,bottom:0,zIndex:9999,background:"repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(0,0,0,0.06) 2px,rgba(0,0,0,0.06) 4px)",pointerEvents:"none",animation:"flicker 12s infinite" }}/>
      <div style={{ minHeight:"100vh",background:"#030303",fontFamily:"'Share Tech Mono',monospace",color:"#00ff41",position:"relative" }}>
        {appPhase==="boot"&&<BootScreen onComplete={()=>setAppPhase("game")}/>}
        {appPhase==="game"&&<LevelScreen key={currentLevel} level={LEVELS[currentLevel]} onSolve={handleSolve}/>}
        {appPhase==="finale"&&<FinaleScreen/>}
      </div>
    </>
  );
}
